import { useTranslation } from 'react-i18next';
import { Button } from 'src/builder/PublicActionPage/components/Button';
import { Meta } from 'src/builder/PublicActionPage/components/Meta';

type Props = {
  actionPage: PublicActionPage;
  isPreview?: boolean;
};

export const LoginLinkSection = ({ actionPage, isPreview }: Props) => {
  const { t } = useTranslation('common');

  const { onClickLogin } = useExpressCheckout({ actionPage, isPreview });

  return (
    <Button
      className="!-mb-4 flex cursor-pointer"
      onClick={isPreview ? undefined : onClickLogin}
      variant="unstyled"
    >
      <Meta className="ml-auto pe-1 !text-neutral-600" variant="regular">
        {t('donorId.haveAccount')}
      </Meta>
      <Meta className="!text-blue-600" variant="regular">
        {t('donorId.signIn')}
      </Meta>
    </Button>
  );
};

